const input = $input.first().json.currentDate;

// Parse original datetime
const date = new Date(input);

// Formatter for Canada Eastern Time
const formatter = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/Toronto',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false,
});

const parts = formatter.formatToParts(date);
const get = (type) => parts.find(p => p.type === type).value;

return {
  date: `${get('year')}-${get('month')}-${get('day')}`,
  time: `${get('hour')}:${get('minute')}`
};

const items = $input.all();

const filtered = items.filter(item => {
  const row = item.json;

  return (
    row["ADMIN ACTION"] === "Approve" &&
    (!row["STATUS LOG"] ||
    row["STATUS LOG"].trim() === "" ||
    row["STATUS LOG"].toLowerCase().startsWith("rejected") ||
    row["STATUS LOG"].toLowerCase() === "ready for review") &&
    (!row["LINK TO GOOGLE DOC"] || row["LINK TO GOOGLE DOC"].trim() === "") &&
    (!row["LINK TO WORDPRESS BACKEND"] || row["LINK TO WORDPRESS BACKEND"].trim() === "")
  );
});

return filtered;

// Get the HTTP response (HTML string)
const html = $input.first().json.data || $input.first().json.body || "";

// Get original sheet data from the loop node (HTTP Request replaces $json with response data)
const originalData = $('Loop Over Items: APPROVED').item.json;

// If HTTP request failed or returned empty/too short HTML
if (!html || html.length < 100) {
  return []; // Empty array = skip this item in the loop silently
}


// Remove non-article elements and their content
let cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, "")
  .replace(/<style[\s\S]*?<\/style>/gi, "")
  .replace(/<nav[\s\S]*?<\/nav>/gi, "")
  .replace(/<header[\s\S]*?<\/header>/gi, "")
  .replace(/<footer[\s\S]*?<\/footer>/gi, "")
  .replace(/<aside[\s\S]*?<\/aside>/gi, "")
  .replace(/<figure[\s\S]*?<\/figure>/gi, "");

// Try to extract from <article> tag first (most news sites use this)
const articleMatch = cleaned.match(/<article[\s\S]*?<\/article>/i);
if (articleMatch) {
  cleaned = articleMatch[0];
}

// Strip all remaining HTML tags
cleaned = cleaned.replace(/<[^>]+>/g, " ");

// Clean up HTML entities and whitespace
cleaned = cleaned
  .replace(/&nbsp;/g, " ")
  .replace(/&amp;/g, "&")
  .replace(/&lt;/g, "<")
  .replace(/&gt;/g, ">")
  .replace(/&#39;/g, "'")
  .replace(/&quot;/g, '"')
  .replace(/\s+/g, " ")
  .trim();

// Take first 2000 characters (~500 words) to avoid token overload
const truncated = cleaned.substring(0, 4000);

// Return original sheet data with scraped CONTENT merged in
return [{
  json: {
    ...originalData,
    CONTENT: truncated
  }
}];

